// shadcn
import { Button } from "@/components/ui/button";

// constants
const plans = [
  {
    id: 1,
    name: "Rookie",
    price: 24,
    description:
      "At half-past eight the door opened, the policeman appeared and requesting.",
    featured: false
  },
  {
    id: 2,
    name: "Master",
    price: 49,
    description:
      "At half-past eight the door opened, the policeman appeared and requesting.",
    featured: true
  },
  {
    id: 3,
    name: "Veteran",
    price: 99,
    description:
      "At half-past eight the door opened, the policeman appeared and requesting.",
    featured: false
  }
];

//  ------------------------------ | PRICING 1 | ------------------------------  //

export default function Pricing1() {
  return (
    <section className="py-20">
      <div className="container mx-auto px-4 sm:px-6 lg:px-8">
        {/* Header */}
        <div className="text-center mb-12 flex flex-col gap-3">
          <h2 className="text-foreground">Pricing Plans</h2>
          <p className="text-muted-foreground max-w-lg mx-auto">
            At half-past eight the door opened, the policeman appeared and
            requesting them to follow him, led way to an adjoining hall.
          </p>
        </div>

        {/* Plans grid */}
        <div className="grid grid-cols-1 sm:grid-cols-3 gap-6">
          {plans.map((plan) => (
            <div
              key={plan.id}
              className="border border-border rounded-2xl p-8 flex flex-col items-center text-center gap-6"
            >
              {/* Plan name */}
              <h4 className="text-foreground font-bold">{plan.name}</h4>

              {/* Price */}
              <div className="flex items-end gap-1.5">
                <span className="text-5xl font-bold text-primary">
                  ${plan.price}
                </span>
                <span className="text-muted-foreground text-md mb-1">
                  /per month
                </span>
              </div>

              {/* Description */}
              <p className="text-muted-foreground text-md">
                {plan.description}
              </p>

              {/* CTA */}
              <Button
                variant={plan.featured ? "default" : "outline"}
                className={
                  plan.featured
                    ? "bg-primary text-primary-foreground w-full"
                    : "w-full border-primary text-primary bg-transparent"
                }
              >
                Get Started
              </Button>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}
